import React, { useState } from 'react';
import { useAuth } from '../hooks/useAuth';
import { Link } from 'react-router-dom';
import { Container, Typography, TextField, Button, Box, Alert } from '@mui/material';
import { useNavigate } from 'react-router-dom';

const LoginForm: React.FC = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState<string | null>(null);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    try {
      await login(username, password);
      navigate('/menu');
    } catch (err: any) {
      setError(err.response?.data?.message || 'Credenciales inválidas');
    }
  };

  return (
    <Box sx={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', bgcolor: '#f0f4f8' }}>
      <Container maxWidth="xs">
        <Box sx={{ bgcolor: 'white', p: 4, borderRadius: 2, boxShadow: 3 }}>
          <Typography variant="h5" align="center" gutterBottom fontWeight="bold">
             Gastos Personales
          </Typography>
          <Typography variant="body2" align="center" color="text.secondary" sx={{ mb: 3 }}>
            Inicia sesión para continuar
          </Typography>
          <Box component="form" onSubmit={handleSubmit}>
            <TextField fullWidth label="Email" margin="normal" required value={username} onChange={e => setUsername(e.target.value)} />
            <TextField fullWidth label="Contraseña" type="password" margin="normal" required value={password} onChange={e => setPassword(e.target.value)} />
            {error && <Alert severity="error" sx={{ mt: 1 }}>{error}</Alert>}
            <Button type="submit" fullWidth variant="contained" sx={{ mt: 3, mb: 2 }} size="large">
              Iniciar Sesión
            </Button>
            <Typography variant="body2" align="center">
              ¿No tienes cuenta? <Link to="/signup">Regístrate</Link>
            </Typography>
          </Box>
        </Box>
      </Container>
    </Box>
  );
};

export default LoginForm;
